from flask import Flask, redirect, url_for, session, request
from flask_session import Session
import requests
import jwt
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)
app.config['SESSION_TYPE'] = 'filesystem'
Session(app)

CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
REDIRECT_URI = 'http://localhost:5000/callback'
AUTHORIZATION_ENDPOINT = 'https://provider.com/authorize'
TOKEN_ENDPOINT = 'https://provider.com/token'
JWKS_URL = 'https://provider.com/.well-known/jwks.json'

@app.route('/')
def index():
    return 'Welcome to the Flask OpenID Connect App! <a href="/login">Login</a>'

@app.route('/login')
def login():
    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'scope': 'openid profile',
        'state': os.urandom(16).hex()
    }
    return redirect(f"{AUTHORIZATION_ENDPOINT}?{requests.compat.urlencode(params)}")

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(TOKEN_ENDPOINT, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    })
    
    token_response_data = token_response.json()
    id_token = token_response_data.get('id_token')
    
    if id_token:
        jwks = requests.get(JWKS_URL).json()
        public_key = get_public_key(jwks, id_token)
        decoded_token = jwt.decode(id_token, public_key, algorithms=['RS256'], audience=CLIENT_ID)
        session['user'] = decoded_token
        return redirect(url_for('profile'))
    return 'Authentication failed', 400

@app.route('/profile')
def profile():
    user = session.get('user')
    if user:
        return f"Hello, {user['name']}! <a href='/logout'>Logout</a>"
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

def get_public_key(jwks, id_token):
    header = jwt.get_unverified_header(id_token)
    for key in jwks['keys']:
        if key['kid'] == header['kid']:
            return jwt.algorithms.RSAAlgorithm.from_jwk(key)
    raise Exception('Public key not found.')

if __name__ == '__main__':
    app.run(debug=True)